const PROCESSING_FEE = 5;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const basePremium = (item: Item): number => {
  if (item.type === "sword") return 100;
  return 0;
};

export const runScenario = (input: Scenario): { results: { premium: number }[] } => {
  const results = input.steps.map((step) => {
    const itemsTotal = step.items.reduce((sum, item) => sum + basePremium(item), 0);
    return { premium: itemsTotal + PROCESSING_FEE };
  });
  return { results };
};

