input.content:
const PROCESSING_FEE = 5;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const componentBasePremium = (items: Item[]): number => {
  const components = items.filter((item) => COMPONENT_TYPES.has(item.type));
  const counts = new Map<string, number>();
  for (const c of components) {
    counts.set(c.type, (counts.get(c.type) ?? 0) + 1);
  }
  let total = 0;
  for (const count of counts.values()) {
    const blocks = Math.floor(count / BLOCK_SIZE);
    const leftover = count - blocks * BLOCK_SIZE;
    total += blocks * BLOCK_PREMIUM + leftover * 25;
  }
  return total;
};

const quotePremium = (items: Item[]): number => {
  const mainItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
  const mainTotal = mainItems.reduce((sum, item) => sum + basePremium(item), 0);
  return mainTotal + componentBasePremium(items) + PROCESSING_FEE;
};

export const runScenario = (input: Scenario): { results: { premium: number }[] } => ({
  results: input.steps.map((step) => ({ premium: quotePremium(step.items) })),
});

