import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / trivial ---
  it("empty item list yields premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums by item type ---
  it("quote for a single plain sword yields 105 G (100 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it("quote for a single plain amulet yields 65 G (60 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 65 }] });
  });
  it("quote for a single plain staff yields 85 G (80 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 85 }] });
  });
  it("quote for a single plain potion yields 45 G (40 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 45 }] });
  });

  // --- Components and building blocks ---
  it("quote for 1 rune yields 30 G (25 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 30 }] });
  });
  it("quote for 2 runes yields 55 G (50 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 55 }] });
  });
  it("quote for 3 runes yields 65 G — block applies (60 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 65 }] });
  });
  it("quote for 4 runes yields 105 G — no block (100 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it.todo("quote for 7 runes yields 180 G (175 base + 5 fee)");
  it.todo("quote for 2 runes + 1 moonstone yields 80 G — no block, different types (75 base + 5 fee)");
  it.todo("quote for 3 runes + 3 moonstones yields 125 G — two separate blocks (120 base + 5 fee)");

  // --- Item-specific modifiers ---
  it.todo("cursed sword (no other modifiers, newcomer's first contract) yields 165 G");
  it.todo("sword with enchantment 5 adds 30% high-enchantment surcharge");
  it.todo("sword with enchantment 4 does NOT add high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 adds both curse and high-enchantment surcharges");

  // --- Policy-wide modifiers ---
  it.todo("customer with exactly 2 years gets 20% loyalty discount");
  it.todo("customer with less than 2 years does not get loyalty discount");
  it.todo("first contract in scenario gets 10% first-insurance surcharge per item");
  it.todo("second contract in scenario gets 15% follow-up discount on policy total");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword + plain amulet: curse applies only to sword (base 160, +50 = 210 before fee)");

  // --- Rounding ---
  it.todo("premium fractional result rounds UP in MHPCO's favor (197.5 -> 198)");
  it.todo("payout fractional result rounds DOWN in MHPCO's favor (350.5 -> 350)");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (enchantment 3, 0 years): premium 165 G");
  it.todo("long-standing customer's second contract with cursed sword (enchantment 7, 3 years): premium 160 G");

  // --- Claim processing: standard reimbursement ---
  it.todo("regular steel sword enchantment 3 damaged 500 G yields payout 400 G (500 - 100 deductible)");
  it.todo("rune damaged 200 G yields payout 100 G (no special clause, deductible 100)");

  // --- Claim processing: high enchantment ---
  it.todo("steel sword enchantment 9 damaged 1000 G yields payout 400 G (50% then -100)");
  it.todo("dragon sword enchantment 8 damaged 1000 G yields payout 400 G (50% wins, then -100)");

  // --- Claim processing: dragon material ---
  it.todo("dragon sword enchantment 5 damaged 800 G yields payout 700 G (full, then -100)");
  it.todo("dragon sword enchantment 9 damaged 1000 G yields payout 400 G (50% wins, then -100)");

  // --- Deductible per damage event ---
  it.todo("two items damaged by dragon: 500 + 300 -> 400 + 200 = 600 G (deductible per item)");

  // --- Multiple items of the same type ---
  it.todo("two swords -> insurance sum 2000, cap 4000");
  it.todo("two sword damages on a two-sword policy: each treated separately");
  it.todo("more damages of a type than insured items rejects the claim (CLI non-zero exit)");

  // --- Cap exhaustion ---
  it.todo("sword + amulet -> insurance sum 1600, cap 3200");
  it.todo("cursed sword -> cap 2000 (premium modifiers don't change cap)");
  it.todo("sword + 3 runes (block) -> insurance sum 1750 (block affects premium only)");
  it.todo("two successive 1500 G claims on sword (cap 2000): payouts 1400 then 600, remaining 0");

  // --- Edge cases / errors ---
  it.todo("quote with unknown item type causes CLI to exit non-zero with stderr error");
  it.todo("claim referencing item not in the policy causes CLI to exit non-zero");
  it.todo("claim with negative damage amount causes CLI to exit non-zero");
});

