const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + (INSURANCE_VALUE_BY_TYPE[item.type] ?? 0), 0);

type Policy = { items: Item[]; capRemaining: number };

const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
  const totalPayout = incident.damages.reduce(
    (sum, damage) => sum + Math.max(0, damage.amount - DEDUCTIBLE),
    0,
  );
  const payout = Math.min(totalPayout, policy.capRemaining);
  policy.capRemaining -= payout;
  return { payout: Math.floor(payout), remainingCap: policy.capRemaining };
};

export const runScenario = (input: Scenario): { results: StepResult[] } => {
  let quoteCount = 0;
  const policies: Policy[] = [];
  const results: StepResult[] = input.steps.map((step) => {
